<?php require __DIR__.'/includes/bootstrap.php';if(!booths_schema_ready())redirect('booth/index.php');if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$action=$_POST['action']??'';if($action==='remove')cart_remove((int)$_POST['product_id']);if($action==='update'){foreach($_POST['qty']??[] as $id=>$qty){$qty=(int)$qty;if($qty<=0)cart_remove((int)$id);else $_SESSION['booth_cart'][(int)$id]=min(99,$qty);}}redirect('cart.php');}$cart=cart_details();app_header('Shopping Cart');?>
<section class="dashboard-hero"><p class="eyebrow">CONVENTION HAUL</p><h1>Your Cart</h1><p>For now, checkout creates a demo order without processing payment.</p></section><section class="cart-layout"><div class="form-card"><form method="post"><?=csrf_field()?><input type="hidden" name="action" value="update"><?php foreach($cart['items'] as $p):?><div class="cart-line"><?php if($p['image_path']):?><img src="<?=e(base_url($p['image_path']))?>" alt=""><?php endif?><div><strong><a href="<?=e(base_url('booth/product.php?slug='.urlencode($p['slug'])))?>"><?=e($p['name'])?></a></strong><span><a href="<?=e(base_url('booth/view.php?slug='.urlencode($p['booth_slug'])))?>"><?=e($p['booth_name'])?></a></span></div><div>$<?=number_format((float)$p['price'],2)?></div><input type="number" min="0" max="99" name="qty[<?=$p['id']?>]" value="<?=$p['quantity']?>"><strong>$<?=number_format((float)$p['line_total'],2)?></strong></div><?php endforeach?><?php if($cart['items']):?><button class="button ghost">Update Cart</button><?php else:?><div class="empty-state"><h2>Your cart is empty</h2><p>Visit a booth and find something worth bringing home.</p><a class="button primary" href="booth/index.php">Browse Booths</a></div><?php endif?></form></div><?php if($cart['items']):?><aside class="app-card cart-summary"><h2>Order Summary</h2><p><span>Subtotal</span><strong>$<?=number_format((float)$cart['subtotal'],2)?></strong></p><p class="muted">Shipping and tax are not calculated in demo mode.</p><a class="button primary large" href="checkout.php">Demo Checkout</a></aside><?php endif?></section><?php app_footer();